import React, { useState, useEffect, useRef } from 'react';
import { useParams } from 'react-router-dom';

const AiPage = () => {
  const { id } = useParams();
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [apiStatus, setApiStatus] = useState('服务就绪');
  const messagesEndRef = useRef(null);
  
  // System prompt based on the current lesson
  const systemPrompts = {
    1: "你是一名密码安全专家，用简单易懂的方式解释密码安全最佳实践，使用表情符号和例子帮助年轻学习者理解。",
    2: "你是一名钓鱼邮件识别专家，帮助用户识别可疑邮件，提供清晰的示例和警告。",
    3: "你是一名移动安全顾问，教授智能手机防盗和防恶意软件的最佳实践。",
    4: "你是一名社交媒体隐私专家，指导用户安全分享和隐私设置。",
    5: "你是一名网页安全专家，解释如何识别安全网站和避免下载陷阱。"
  };

  const systemPrompt = systemPrompts[id] || "你是一名网络安全助手，用中文回答问题。";

  // Initial welcome message based on lesson
  useEffect(() => {
    const welcomeMessages = {
      1: "你好！我是你的密码安全助手。可以问我关于创建强密码、双重认证或密码管理器的问题！🔐",
      2: "你好！我是你的钓鱼邮件识别助手。可以给我看可疑邮件或询问如何识别骗局！🎣",
      3: "你好！我是你的手机安全向导。可以问我关于手机锁屏、应用安全或防盗的问题！📱",
      4: "你好！我是你的社交媒体隐私教练。可以问我关于安全分享、好友列表或工作政策的问题！👥",
      5: "你好！我是你的网页安全顾问。可以问我关于安全网站、网址检查或安全下载的问题！🌐"
    };
    
    setMessages([{ role: 'assistant', content: welcomeMessages[id] || "你好！我是你的网络安全助手。今天有什么可以帮你的吗？" }]);
  }, [id]);

  // 自动滚动到底部
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = { role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);
    setApiStatus('请求处理中...');

    try {
      // 添加请求超时控制
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 10000);

      const response = await fetch('https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions', {
        method: 'POST',
        signal: controller.signal,
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${process.env.REACT_APP_DASHSCOPE_API_KEY || 'sk-9d42b587f3364ece9f70fed4b464c17d'}`,
        },
        body: JSON.stringify({
          model: 'qwen-turbo',
          messages: [
            {
              role: 'system',
              content: systemPrompt
            },
            ...messages.slice(-6), // 保持最近对话上下文
            userMessage
          ]
        })
      });
      clearTimeout(timeoutId);

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`HTTP ${response.status}: ${errorText.slice(0, 100)}`);
      }

      const data = await response.json();
      
      if (!data.choices?.[0]?.message?.content) {
        throw new Error('API返回格式异常');
      }

      setMessages(prev => [...prev, {
        role: 'assistant',
        content: data.choices[0].message.content
      }]);
      setApiStatus('请求成功');

    } catch (error) {
      console.error('API调用失败:', error);
      
      let errorMsg = '服务异常';
      if (error.name === 'AbortError') {
        errorMsg = '请求超时，请重试';
      } else if (error.message.includes('401')) {
        errorMsg = 'API密钥无效';
      } else if (error.message.includes('404')) {
        errorMsg = 'API端点不存在';
      }

      setMessages(prev => [...prev, {
        role: 'assistant',
        content: `⚠️ 请求失败\n${errorMsg}\n${error.message}`
      }]);
      setApiStatus(`错误: ${errorMsg}`);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="content-card">
      <div className="p-4 max-w-3xl mx-auto">
        {/* 状态栏 */}
        <div className={`mb-2 px-3 py-2 rounded-lg text-sm ${
          apiStatus.includes('失败') || apiStatus.includes('异常') 
            ? 'bg-red-50 text-red-800' 
            : apiStatus.includes('正在') 
              ? 'bg-blue-50 text-blue-800' 
              : 'bg-green-50 text-green-800'
        }`}>
          <div className="flex justify-between items-center">
            <span>
              <span className="font-medium">状态:</span> {apiStatus}
            </span>
            {process.env.NODE_ENV === 'development' && (
              <span className="text-xs bg-white/30 px-2 py-1 rounded">
                开发模式
              </span>
            )}
          </div>
        </div>

        <h2 className="text-center text-2xl font-semibold text-teal-700 mb-4">
          💬 AI 助手 - 第 {id} 课
        </h2>
        
        {/* 消息区域 */}
        <div className="mb-4 space-y-3 h-[65vh] overflow-y-auto p-2">
          {messages.map((msg, i) => (
            <div 
              key={i} 
              className={`p-3 rounded-lg max-w-[90%] ${
                msg.role === 'user' 
                  ? 'ml-auto bg-blue-600 text-white rounded-br-none' 
                  : 'mr-auto bg-white border border-gray-200 rounded-bl-none shadow-sm'
              }`}
            >
              {msg.content.split('\n').map((line, idx) => (
                <p key={idx} className="whitespace-pre-wrap">{line}</p>
              ))}
            </div>
          ))}
          
          {isLoading && (
            <div className="mr-auto bg-white p-3 rounded-lg rounded-bl-none max-w-[90%] border border-gray-200 shadow-sm">
              <div className="flex items-center space-x-2 text-gray-600">
                <span className="relative flex h-3 w-3">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500"></span>
                </span>
                <span>正在生成回答...</span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* 输入区域 */}
        <form onSubmit={handleSubmit} className="sticky bottom-4 bg-white p-3 rounded-xl border border-gray-200 shadow-lg">
          <div className="flex gap-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="输入网络安全问题..."
              className="flex-1 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              disabled={isLoading}
              autoFocus
            />
            <button
              type="submit"
              disabled={isLoading || !input.trim()}
              className="px-5 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center"
            >
              {isLoading ? (
                <>
                  <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  发送中
                </>
              ) : '发送'}
            </button>
          </div>
          <p className="mt-2 text-xs text-gray-500 text-center">
            由阿里云通义千问提供支持 · 回答可能有不准确之处
          </p>
        </form>
      </div>
    </div>
  );
};

export default AiPage;
